        return digits;
    }

    // Calculate n squared and n cubed
    const n2 = n * n;
    const n3 = n * n * n;

    // Convert to hexadecimal (base 16) and base36
    const hex = convertToBase(n2, 16);
    const base36 = convertToBase(n3, 36);

    // Concatenate and return the result
    return hex + base36;
}
